import { type CSSProperties, useEffect, useMemo, useRef, useState } from 'react';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import { RealtimeChannel } from '@supabase/supabase-js';
import { supabase } from '../lib/supabase';
import { useAuth } from '../context/AuthContext';
import {
  ensureTableStateCache,
  getCachedTableState,
  setCachedTableState,
  watchCachedTableState,
  type TablePlayer,
  type TableState,
  type WireCard,
} from '../lib/tableStateCache';
import styles from './Game.module.css';

type ProfileRow = {
  user_id: string;
  username: string;
};

type PlayerAction = 'FOLD' | 'CHECK' | 'CALL' | 'RAISE';

const SEATS = [
  styles.seatLeft,
  styles.seatTopLeft,
  styles.seatTop,
  styles.seatTopRight,
  styles.seatRight,
  styles.seatBottom,
];

const RAISE_PRESETS = [20, 33, 50, 75, 100, 150, 200];
const ACTION_TIMEOUT_MS = 15_000;

function formatCard(card: WireCard | undefined) {
  if (!card) return '?';

  const value = card._value ?? card.value;
  const color = card._color ?? card.color;
  const valueLabel = value === 1 ? 'A' : value === 13 ? 'K' : value === 12 ? 'Q' : value === 11 ? 'J' : String(value ?? '?');
  const suit = color === 0 ? 'â™ ' : color === 1 ? 'â™Ą' : color === 2 ? 'â™¦' : 'â™Ł';

  return `${valueLabel}${suit}`;
}

function isRedCard(card: WireCard | undefined) {
  const color = card?._color ?? card?.color;
  return color === 1 || color === 2;
}

function formatClock(ms: number) {
  const totalSeconds = Math.max(0, Math.ceil(ms / 1000));
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}:${String(seconds).padStart(2, '0')}`;
}

function formatChips(value: number) {
  return Number.isInteger(value) ? String(value) : value.toFixed(1);
}

function formatStack(player: TablePlayer | null | undefined, bigBlind: number | undefined, unit: 'BB' | 'C') {
  if (!player) return '';
  if (unit === 'C' || !bigBlind) return `${formatChips(player.chips)}C`;
  const stack = player.chips / bigBlind;
  return `${Number.isInteger(stack) ? stack : stack.toFixed(1)}BB`;
}

function formatBet(value: number | undefined, bigBlind: number | undefined, unit: 'BB' | 'C') {
  if (!value) return '';
  if (unit === 'C' || !bigBlind) return `${formatChips(value)}C`;
  const bet = value / bigBlind;
  return `${Number.isInteger(bet) ? bet : bet.toFixed(1)}BB`;
}

function getUserDisplayName(user: { user_metadata?: Record<string, unknown>; email?: string } | null | undefined) {
  const metadata = user?.user_metadata ?? {};
  const name = metadata.username ?? metadata.pseudo ?? metadata.name;
  return typeof name === 'string' && name.trim() ? name : user?.email?.split('@')[0] ?? 'Toi';
}

function extractLatestTableState(rawState: unknown): TableState | null {
  if (!rawState || typeof rawState !== 'object') return null;

  const state = rawState as Record<string, Array<{ payload?: unknown }>>;
  let latest: TableState | null = null;

  for (const presences of Object.values(state)) {
    if (!Array.isArray(presences)) continue;
    for (const presence of presences) {
      const payload = presence?.payload as Partial<TableState> | undefined;
      if (payload && typeof payload.id === 'number' && Array.isArray(payload.players)) {
        latest = payload as TableState;
      }
    }
  }

  return latest;
}

function statusLabel(status: TableState['game_status'] | undefined) {
  if (status === 0 || status === '0' || status === 'WAITING') return 'En attente';
  if (status === 1 || status === '1' || status === 'PLAYING') return 'En cours';
  if (status === 2 || status === '2' || status === 'PAUSED') return 'En pause';
  if (status === 3 || status === '3' || status === 'ENDED') return 'TerminĂ©';
  return 'Connexion';
}

async function removeExistingChannel(topic: string) {
  const channels = supabase.getChannels?.() ?? [];
  const existing = channels.find(channel => channel.topic === `realtime:${topic}`);
  if (existing) {
    existing.unsubscribe();
    await supabase.removeChannel(existing);
  }
}

export default function Game() {
  const navigate = useNavigate();
  const location = useLocation();
  const { tableId } = useParams();
  const { user, loading: authLoading } = useAuth();

  const [table, setTable] = useState<TableState | null>(null);
  const [privateCards, setPrivateCards] = useState<WireCard[]>([]);
  const [readyForAction, setReadyForAction] = useState(false);
  const [raiseTo, setRaiseTo] = useState('');
  const [feedback, setFeedback] = useState('Connexion Ă  la table...');
  const [selectedAction, setSelectedAction] = useState<PlayerAction | null>(null);
  const [actionChannel, setActionChannel] = useState<RealtimeChannel | null>(null);
  const [stackUnit, setStackUnit] = useState<'BB' | 'C'>('BB');
  const [actionDeadline, setActionDeadline] = useState<number | null>(null);
  const [now, setNow] = useState(Date.now());
  const tableReceivedRef = useRef(false);

  const numericTableId = Number(tableId);
  const lobbyTournamentId = (location.state as { tournamentId?: number } | null)?.tournamentId;
  const potTotal = useMemo(() => table?.pot.reduce((sum, value) => sum + value, 0) ?? 0, [table]);
  const heroSeatIndex = useMemo(() => table?.players.findIndex(player => player?.id === user?.id) ?? -1, [table, user]);
  const isHeroTurn = Boolean(table && heroSeatIndex >= 0 && table.playerToPlay === heroSeatIndex);
  const actionTimeLeftMs = actionDeadline ? Math.max(0, actionDeadline - now) : 0;
  const actionProgress = actionDeadline ? Math.max(0, Math.min(1, actionTimeLeftMs / ACTION_TIMEOUT_MS)) : 0;
  const visiblePlayers = useMemo(() => {
    const players = table?.players ?? [];
    const filled = players.filter(Boolean) as TablePlayer[];
    const hero = filled.find(player => player.id === user?.id) ?? (heroSeatIndex >= 0 ? table?.players[heroSeatIndex] ?? null : null);
    const opponents = filled.filter(player => player.id !== user?.id).slice(0, 5);
    return {
      opponents,
      hero,
    };
  }, [heroSeatIndex, table, user?.id]);

  useEffect(() => {
    const interval = window.setInterval(() => setNow(Date.now()), 250);
    return () => window.clearInterval(interval);
  }, []);

  useEffect(() => {
    if (isHeroTurn || readyForAction) {
      setActionDeadline(current => current && current > Date.now() ? current : Date.now() + ACTION_TIMEOUT_MS);
    } else {
      setActionDeadline(null);
    }
  }, [isHeroTurn, readyForAction, table?.playerToPlay]);

  useEffect(() => {
    if (authLoading) return;
    if (!user) {
      navigate('/');
      return;
    }
    if (!Number.isFinite(numericTableId)) {
      setFeedback('Table introuvable.');
      return;
    }

    let mounted = true;
    const channels: RealtimeChannel[] = [];
    let stateTimeout: number | undefined;
    let fallbackInterval: number | undefined;

    const setup = async () => {
      tableReceivedRef.current = false;
      setFeedback('Connexion Ă  la table...');

      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.access_token) {
        navigate('/login');
        return;
      }

      supabase.realtime.setAuth(session.access_token);

      const cached = getCachedTableState(numericTableId);
      if (cached) {
        setTable(cached);
        tableReceivedRef.current = true;
        setFeedback('');
      }

      const unwatchCache = watchCachedTableState(numericTableId, state => {
        if (!mounted) return;
        tableReceivedRef.current = true;
        setTable(state);
        setFeedback('');
      });

      const applyTableState = (payload: unknown) => {
        if (!mounted || !payload || typeof payload !== 'object') return;
        const next = payload as TableState;
        if (typeof next.id === 'number' && Array.isArray(next.players)) {
          tableReceivedRef.current = true;
          setCachedTableState(next);
          setTable(next);
          setFeedback('');
        }
      };

      const requestSnapshot = (channel: RealtimeChannel) => {
        void channel.send({
          type: 'broadcast',
          event: 'snapshot_request',
          payload: {
            playerId: user.id,
          },
        });
      };

      const fetchTableFallback = async () => {
        if (tableReceivedRef.current) return;

        const { data: tableRow } = await supabase
          .from('poker-tables')
          .select('id, players')
          .eq('id', numericTableId)
          .maybeSingle();

        const rawPlayers = tableRow?.players;
        const playerIds = Array.isArray(rawPlayers)
          ? rawPlayers.filter((id): id is string => typeof id === 'string')
          : [];
        if (!tableRow?.id || playerIds.length === 0 || tableReceivedRef.current) return;

        const { data: profileRows } = await supabase
          .from('profiles')
          .select('user_id, username')
          .in('user_id', playerIds);
        const profiles = (profileRows ?? []) as ProfileRow[];

        const fallbackPlayers = playerIds.map(playerId => {
          const profile = profiles.find(item => item.user_id === playerId);
          return {
            id: playerId,
            name: profile?.username ?? 'Joueur',
            has_cards: false,
            chips: 1000,
            bet: 0,
          };
        });

        const fallbackState = {
          id: tableRow.id,
          common_cards: [],
          players: fallbackPlayers,
          pot: [],
          button: 0,
          playerToPlay: null,
          BB: 50,
          SB: 25,
          game_status: 'PLAYING',
        };
        setCachedTableState(fallbackState);
        setTable(fallbackState);
        setFeedback('Ă‰tat temps rĂ©el en attente, affichage de secours.');
      };

      void ensureTableStateCache(numericTableId);

      await removeExistingChannel(`table:${numericTableId}:private-user:${user.id}`);
      const privateChannel = supabase.channel(`table:${numericTableId}:private-user:${user.id}`, {
        config: { private: true },
      });
      channels.push(privateChannel);

      privateChannel
        .on('broadcast', { event: 'info' }, ({ payload }) => {
          const card = (payload as { card?: WireCard } | undefined)?.card;
          if (!card) return;
          setPrivateCards(current => current.length >= 2 ? [card] : [...current, card]);
        })
        .on('broadcast', { event: 'ready' }, () => {
          setReadyForAction(true);
          setFeedback('Ă€ toi de jouer.');
        });

      await removeExistingChannel(`table:${numericTableId}:action-user:${user.id}`);
      const tableActionChannel = supabase.channel(`table:${numericTableId}:action-user:${user.id}`);
      channels.push(tableActionChannel);
      setActionChannel(tableActionChannel);

      tableActionChannel.on('broadcast', { event: 'ready' }, () => {
        setReadyForAction(true);
        setFeedback('Ă€ toi de jouer.');
      });

      const tableSpectatorChannel = supabase.channel(`table:${numericTableId}:spectator`);
      channels.push(tableSpectatorChannel);

      tableSpectatorChannel
        .on('broadcast', { event: 'state' }, ({ payload }) => {
          applyTableState(payload);
        })
        .on('presence', { event: 'sync' }, () => {
          const latest = extractLatestTableState(tableSpectatorChannel.presenceState());
          if (latest) applyTableState(latest);
        });

      await removeExistingChannel(`table:${numericTableId}:state`);
      const tableStateChannel = supabase.channel(`table:${numericTableId}:state`, {
        config: { private: true },
      });
      channels.push(tableStateChannel);

      tableStateChannel
        .on('broadcast', { event: 'state' }, ({ payload }) => {
          applyTableState(payload);
        })
        .on('presence', { event: 'sync' }, () => {
          const latest = extractLatestTableState(tableStateChannel.presenceState());
          if (latest) applyTableState(latest);
        });

      stateTimeout = window.setTimeout(() => {
        if (mounted && !tableReceivedRef.current) {
          setFeedback("En attente de l'Ă©tat de la table...");
          void fetchTableFallback();
        }
      }, 8000);

      fallbackInterval = window.setInterval(fetchTableFallback, 5000);

      for (const channel of channels) {
        channel.subscribe((status) => {
          if (status === 'SUBSCRIBED' && (channel === tableStateChannel || channel === tableSpectatorChannel)) {
            requestSnapshot(channel);
          }

          if ((status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') && (channel === tableStateChannel || channel === tableSpectatorChannel) && !tableReceivedRef.current) {
            setFeedback("En attente de l'Ă©tat de la table...");
          }
        });
      }

      return unwatchCache;
    };

    let cleanupWatch: (() => void) | undefined;
    void setup().then(cleanup => {
      cleanupWatch = cleanup;
    });

    return () => {
      mounted = false;
      cleanupWatch?.();
      if (stateTimeout) window.clearTimeout(stateTimeout);
      if (fallbackInterval) window.clearInterval(fallbackInterval);
      for (const channel of channels) {
        channel.unsubscribe();
        supabase.removeChannel(channel);
      }
      setActionChannel(null);
    };
  }, [authLoading, navigate, numericTableId, user]);

  const sendAction = async (action: PlayerAction) => {
    if (!user || !actionChannel) return;

    setSelectedAction(action);
    window.setTimeout(() => setSelectedAction(current => current === action ? null : current), 180);

    const payload: Record<string, unknown> = { action, playerId: user.id };
    if (action === 'CALL') payload.amount = 0;
    if (action === 'RAISE') {
      const parsed = Number.parseInt(raiseTo, 10);
      if (!Number.isFinite(parsed) || parsed <= 0) {
        setFeedback('Entre un montant de relance valide.');
        return;
      }
      payload.raiseTo = parsed;
    }

    await actionChannel.send({
      type: 'broadcast',
      event: 'player_action',
      payload,
    });

    setReadyForAction(false);
    setActionDeadline(null);
    setFeedback('Action envoyĂ©e.');
  };

  return (
    <div className={styles.page}>
      <button className={`${styles.iconButton} ${styles.homeButton}`} onClick={() => navigate('/tournaments')} aria-label="Retour aux tournois">
        <span />
      </button>
      <button
        className={`${styles.iconButton} ${styles.lobbyButton}`}
        onClick={() => navigate(lobbyTournamentId ? `/tournament-lobby/${lobbyTournamentId}` : '/tournaments')}
        aria-label="Lobby du tournoi"
      >
        <span />
      </button>

      <main className={styles.arena}>
        <section className={styles.table}>
          <div className={styles.outerRail} />
          <div className={styles.innerFelt}>
            <div className={styles.board}>
              <div className={styles.communityCards}>
                {Array.from({ length: 5 }).map((_, index) => {
                  const card = table?.common_cards[index];
                  return (
                    <div key={index} className={`${styles.card} ${styles.boardCard} ${card ? styles.cardVisible : styles.cardSlot} ${isRedCard(card) ? styles.redCard : ''}`}>
                      {card ? formatCard(card) : ''}
                    </div>
                  );
                })}
              </div>
              {potTotal > 0 && <div className={styles.pot}>Pot {potTotal}</div>}
            </div>
          </div>
        </section>

        {visiblePlayers.opponents.map((player, index) => {
          const tableIndex = table?.players.findIndex(candidate => candidate?.id === player.id) ?? -1;
          return (
            <div
              key={player.id ?? index}
              className={`${styles.player} ${SEATS[index] ?? styles.seatTop} ${table?.playerToPlay === tableIndex ? styles.playerActive : ''}`}
            >
              <div className={styles.avatar}>{(player.name ?? '?').slice(0, 1).toUpperCase()}</div>
              <div className={styles.opponentCards}>
                {[0, 1].map(cardIndex => (
                  <div key={cardIndex} className={`${styles.card} ${styles.smallCard} ${player.has_cards ? styles.cardBack : styles.cardSlot}`}>
                    {''}
                  </div>
                ))}
              </div>
              {player.bet ? <div className={styles.bet}>{formatBet(player.bet, table?.BB, stackUnit)}</div> : null}
              <div className={styles.playerName}>{player.name ?? 'Joueur'}</div>
              <div className={styles.playerStack}>{formatStack(player, table?.BB, stackUnit)}</div>
              {table?.button === tableIndex && <div className={styles.dealer}>D</div>}
            </div>
          );
        })}

        <div className={`${styles.player} ${styles.heroPlayer} ${isHeroTurn ? styles.playerActive : ''}`}>
          <div className={styles.heroCards}>
            {[0, 1].map(index => {
              const card = privateCards[index] ?? visiblePlayers.hero?.cards?.[index];
              return (
                <div key={index} className={`${styles.card} ${styles.heroCard} ${card ? styles.cardVisible : styles.cardBack} ${isRedCard(card) ? styles.redCard : ''}`}>
                  {card ? formatCard(card) : ''}
                </div>
              );
            })}
          </div>
          <div className={styles.heroInfo}>
            <div className={styles.playerName}>{visiblePlayers.hero?.name ?? getUserDisplayName(user)}</div>
            <div className={styles.playerStack}>{formatStack(visiblePlayers.hero, table?.BB, stackUnit) || '-'}</div>
          </div>
        </div>

        <section className={styles.controls} aria-label="Actions">
          {(isHeroTurn || readyForAction) && (
            <div className={styles.actionTimer} style={{ '--action-progress': actionProgress } as CSSProperties}>
              <span>{formatClock(actionTimeLeftMs)}</span>
              <div />
            </div>
          )}
          <div className={styles.presetRow}>
            {RAISE_PRESETS.map(percent => (
              <button key={percent} className={styles.presetBtn} onClick={() => setRaiseTo(String(percent))}>
                {percent}%
              </button>
            ))}
          </div>
          <div className={styles.actionRow}>
            {(['FOLD', 'CHECK', 'RAISE'] as PlayerAction[]).map(action => (
              <button
                key={action}
                className={`${styles.actionBtn} ${selectedAction === action ? styles.actionBtnSelected : ''}`}
                disabled={!readyForAction && !isHeroTurn}
                onClick={() => sendAction(action)}
              >
                {action === 'FOLD' ? 'Fold' : action === 'CHECK' ? 'Check' : 'Raise'}
              </button>
            ))}
            <button
              className={`${styles.actionBtn} ${styles.callBtn} ${selectedAction === 'CALL' ? styles.actionBtnSelected : ''}`}
              disabled={!readyForAction && !isHeroTurn}
              onClick={() => sendAction('CALL')}
            >
              {raiseTo ? `${raiseTo}BB` : 'Call'}
            </button>
          </div>
          <input
            className={styles.raiseInput}
            value={raiseTo}
            onChange={event => setRaiseTo(event.target.value)}
            placeholder="Relance"
            inputMode="numeric"
            aria-label="Montant de relance"
          />
          <p className={styles.feedback}>{feedback || (isHeroTurn ? 'Ă€ toi de jouer.' : 'En attente des autres joueurs.')}</p>
        </section>

        <footer className={styles.tableInfo}>
          <span>{statusLabel(table?.game_status)}</span>
          <span>Niveau 1 : {table?.SB ?? '-'}/{table?.BB ?? '-'}</span>
          <button className={styles.unitToggle} onClick={() => setStackUnit(current => current === 'BB' ? 'C' : 'BB')}>
            {stackUnit}
          </button>
        </footer>
      </main>
    </div>
  );
}
